# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import os
import json
import hashlib
from datetime import datetime
from collections import Counter, defaultdict
from flask import Flask, request, jsonify
import numpy as np
from PIL import Image
import io
import base64
import pickle
from sklearn.neural_network import MLPClassifier
from threading import Lock

app = Flask(__name__)

class DataLabelingSystem:
    def __init__(self, data_dir='labeled_data'):
        self.data_dir = data_dir
        self.annotations_file = os.path.join(data_dir, 'annotations.json')
        self.images_dir = os.path.join(data_dir, 'images')
        self.model_file = os.path.join(data_dir, 'model.pkl')
        
        os.makedirs(self.data_dir, exist_ok=True)
        os.makedirs(self.images_dir, exist_ok=True)
        
        self.annotations = self._load_annotations()
        self.model = None
        self.label_encoder = {}
        self.reverse_label_encoder = {}
        self.lock = Lock()
        
    def _load_annotations(self):
        if os.path.exists(self.annotations_file):
            with open(self.annotations_file, 'r') as f:
                return json.load(f)
        return {}
    
    def _save_annotations(self):
        with open(self.annotations_file, 'w') as f:
            json.dump(self.annotations, f, indent=2)
    
    def _get_image_hash(self, image_data):
        return hashlib.sha256(image_data).hexdigest()
    
    def add_annotation(self, image_data, label, annotator_id):
        with self.lock:
            image_hash = self._get_image_hash(image_data)
            
            image_path = os.path.join(self.images_dir, f'{image_hash}.png')
            if not os.path.exists(image_path):
                image = Image.open(io.BytesIO(image_data))
                image.save(image_path)
            
            if image_hash not in self.annotations:
                self.annotations[image_hash] = {
                    'image_path': image_path,
                    'labels': [],
                    'annotators': [],
                    'timestamps': []
                }
            
            annotation_entry = self.annotations[image_hash]
            
            if annotator_id in annotation_entry['annotators']:
                idx = annotation_entry['annotators'].index(annotator_id)
                annotation_entry['labels'][idx] = label
                annotation_entry['timestamps'][idx] = datetime.now().isoformat()
            else:
                annotation_entry['labels'].append(label)
                annotation_entry['annotators'].append(annotator_id)
                annotation_entry['timestamps'].append(datetime.now().isoformat())
            
            self._save_annotations()
            
            return image_hash
    
    def get_aggregated_labels(self):
        aggregated = {}
        
        for image_hash, annotation_data in self.annotations.items():
            if annotation_data['labels']:
                label_counts = Counter(annotation_data['labels'])
                majority_label = label_counts.most_common(1)[0][0]
                confidence = label_counts[majority_label] / len(annotation_data['labels'])
                
                aggregated[image_hash] = {
                    'label': majority_label,
                    'confidence': confidence,
                    'vote_counts': dict(label_counts),
                    'total_votes': len(annotation_data['labels']),
                    'image_path': annotation_data['image_path']
                }
        
        return aggregated
    
    def get_annotation_stats(self):
        stats = {
            'total_images': len(self.annotations),
            'total_annotations': 0,
            'annotators': set(),
            'labels': defaultdict(int)
        }
        
        for annotation_data in self.annotations.values():
            stats['total_annotations'] += len(annotation_data['labels'])
            stats['annotators'].update(annotation_data['annotators'])
            for label in annotation_data['labels']:
                stats['labels'][label] += 1
        
        stats['annotators'] = len(stats['annotators'])
        stats['labels'] = dict(stats['labels'])
        
        return stats
    
    def _preprocess_image(self, image_path, target_size=(64, 64)):
        img = Image.open(image_path).convert('RGB')
        img = img.resize(target_size)
        img_array = np.array(img).flatten() / 255.0
        return img_array
    
    def train_model(self):
        aggregated_labels = self.get_aggregated_labels()
        
        if len(aggregated_labels) == 0:
            return {'status': 'error', 'message': 'No labeled data available'}
        
        X = []
        y = []
        
        unique_labels = set()
        for data in aggregated_labels.values():
            unique_labels.add(data['label'])
        
        self.label_encoder = {label: idx for idx, label in enumerate(sorted(unique_labels))}
        self.reverse_label_encoder = {idx: label for label, idx in self.label_encoder.items()}
        
        for image_hash, data in aggregated_labels.items():
            try:
                features = self._preprocess_image(data['image_path'])
                X.append(features)
                y.append(self.label_encoder[data['label']])
            except Exception as e:
                continue
        
        if len(X) == 0:
            return {'status': 'error', 'message': 'Failed to process images'}
        
        X = np.array(X)
        y = np.array(y)
        
        self.model = MLPClassifier(
            hidden_layer_sizes=(128, 64),
            max_iter=500,
            random_state=42,
            early_stopping=False
        )
        
        self.model.fit(X, y)
        
        with open(self.model_file, 'wb') as f:
            pickle.dump({
                'model': self.model,
                'label_encoder': self.label_encoder,
                'reverse_label_encoder': self.reverse_label_encoder
            }, f)
        
        return {
            'status': 'success',
            'num_samples': len(X),
            'num_classes': len(unique_labels),
            'classes': list(unique_labels)
        }
    
    def predict(self, image_data):
        if self.model is None:
            if os.path.exists(self.model_file):
                with open(self.model_file, 'rb') as f:
                    model_data = pickle.load(f)
                    self.model = model_data['model']
                    self.label_encoder = model_data['label_encoder']
                    self.reverse_label_encoder = model_data['reverse_label_encoder']
            else:
                return {'status': 'error', 'message': 'Model not trained yet'}
        
        temp_path = os.path.join(self.images_dir, 'temp_predict.png')
        image = Image.open(io.BytesIO(image_data))
        image.save(temp_path)
        
        try:
            features = self._preprocess_image(temp_path)
            features = features.reshape(1, -1)
            
            prediction_idx = self.model.predict(features)[0]
            probabilities = self.model.predict_proba(features)[0]
            
            predicted_label = self.reverse_label_encoder[prediction_idx]
            confidence = float(probabilities[prediction_idx])
            
            all_predictions = {
                self.reverse_label_encoder[i]: float(prob) 
                for i, prob in enumerate(probabilities)
            }
            
            return {
                'status': 'success',
                'predicted_label': predicted_label,
                'confidence': confidence,
                'all_probabilities': all_predictions
            }
        finally:
            if os.path.exists(temp_path):
                os.remove(temp_path)

labeling_system = DataLabelingSystem()

@app.route('/api/annotate', methods=['POST'])
def annotate():
    try:
        data = request.get_json()
        
        if 'image' not in data or 'label' not in data or 'annotator_id' not in data:
            return jsonify({'status': 'error', 'message': 'Missing required fields'}), 400
        
        image_b64 = data['image']
        label = data['label']
        annotator_id = data['annotator_id']
        
        image_data = base64.b64decode(image_b64)
        
        image_hash = labeling_system.add_annotation(image_data, label, annotator_id)
        
        return jsonify({
            'status': 'success',
            'image_hash': image_hash,
            'message': 'Annotation added successfully'
        })
    
    except Exception as e:
        return jsonify({'status': 'error', 'message': str(e)}), 500

@app.route('/api/labels/aggregated', methods=['GET'])
def get_aggregated():
    try:
        aggregated = labeling_system.get_aggregated_labels()
        
        result = {}
        for image_hash, data in aggregated.items():
            result[image_hash] = {
                'label': data['label'],
                'confidence': data['confidence'],
                'vote_counts': data['vote_counts'],
                'total_votes': data['total_votes']
            }
        
        return jsonify({
            'status': 'success',
            'aggregated_labels': result
        })
    
    except Exception as e:
        return jsonify({'status': 'error', 'message': str(e)}), 500

@app.route('/api/stats', methods=['GET'])
def get_stats():
    try:
        stats = labeling_system.get_annotation_stats()
        return jsonify({
            'status': 'success',
            'stats': stats
        })
    
    except Exception as e:
        return jsonify({'status': 'error', 'message': str(e)}), 500

@app.route('/api/train', methods=['POST'])
def train():
    try:
        result = labeling_system.train_model()
        return jsonify(result)
    
    except Exception as e:
        return jsonify({'status': 'error', 'message': str(e)}), 500

@app.route('/api/predict', methods=['POST'])
def predict():
    try:
        data = request.get_json()
        
        if 'image' not in data:
            return jsonify({'status': 'error', 'message': 'Missing image field'}), 400
        
        image_b64 = data['image']
        image_data = base64.b64decode(image_b64)
        
        result = labeling_system.predict(image_data)
        return jsonify(result)
    
    except Exception as e:
        return jsonify({'status': 'error', 'message': str(e)}), 500

@app.route('/api/annotations/<image_hash>', methods=['GET'])
def get_annotations(image_hash):
    try:
        if image_hash not in labeling_system.annotations:
            return jsonify({'status': 'error', 'message': 'Image not found'}), 404
        
        annotation_data = labeling_system.annotations[image_hash]
        
        return jsonify({
            'status': 'success',
            'image_hash': image_hash,
            'labels': annotation_data['labels'],
            'annotators': annotation_data['annotators'],
            'timestamps': annotation_data['timestamps']
        })
    
    except Exception as e:
        return jsonify({'status': 'error', 'message': str(e)}), 500

@app.route('/api/health', methods=['GET'])
def health():
    return jsonify({'status': 'healthy', 'message': 'Data labeling system is running'})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)